index 456f5086309c..28b43c815116 100644
--- a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
+++ b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
@@ -633,12 +633,24 @@ static Decomposition decompose(Value *V,
   }

   if (match(V, m_NUWSub(m_Value(Op0), m_Value(Op1)))) {
+    auto *Sub = dyn_cast<BinaryOperator>(V);
+    if (!Sub || !Sub->hasNoUnsignedWrap())
+      return {V, IsKnownNonNegative};
     auto ResA = decompose(Op0, Preconditions, IsSigned, DL);
     auto ResB = decompose(Op1, Preconditions, IsSigned, DL);
     ResA.sub(ResB);
     return ResA;
   }

+  if (match(V, m_Intrinsic<Intrinsic::usub_sat>(m_Value(Op0),
+                                                 m_ConstantInt(CI))) &&
+      !CI->isZero()) {
+    Preconditions.emplace_back(CmpInst::ICMP_UGE, Op0, CI);
+    auto Res = decompose(Op0, Preconditions, IsSigned, DL);
+    Res.Offset = addWithOverflow(Res.Offset, -CI->getSExtValue());
+    return Res;
+  }
+
   return {V, IsKnownNonNegative};
 }

